const now = new Date();
const end = new Date(now.getFullYear(), now.getMonth(), now.getDate());
const start = new Date(end);
const day = start.getDay();
start.setDate(start.getDate() - (day === 0 ? 6 : day - 1));
const iso = date => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const dayOfMonth = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${dayOfMonth}`;
};
const display = date => date.toLocaleDateString('en-GB');
const getText = block => {
  const content = block && block[block.type];
  return content ? (content.rich_text || []).map(text => text.plain_text || '').join('') : '';
};
const weekStart = display(start);
const weekEnd = display(end);
const exists = $input.all().some(item => {
  const block = item.json || {};
  if (block.type !== 'heading_1' && block.type !== 'heading_2') return false;
  const text = getText(block);
  return text.includes('Weekly Review') && text.includes(weekStart) && text.includes(weekEnd);
});
if (exists) return [];
return [{ json: { week_start: weekStart, week_end: weekEnd, start_iso: iso(start), end_iso: iso(end) } }];

const period = $('Prepare review period').first().json || {};
const start = new Date(period.start_iso + 'T00:00:00');
const end = new Date(period.end_iso + 'T23:59:59.999');
const dayMs = 86400000;
const parseDate = value => {
  if (!value) return null;
  const date = new Date(value);
  return Number.isFinite(date.getTime()) ? date : null;
};
const inPeriod = value => {
  const date = parseDate(value);
  return Boolean(date && date >= start && date <= end);
};
const ageDays = value => {
  const date = parseDate(value);
  if (!date) return null;
  return Math.floor((end - date) / dayMs);
};
const getText = block => {
  if (typeof block.content === 'string') return block.content;
  const content = block[block.type];
  return content ? (content.rich_text || []).map(text => text.plain_text || '').join('') : '';
};
const normalize = value => (value || '').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9]+/g, '');
const toText = value => {
  if (value === undefined || value === null) return '';
  if (Array.isArray(value)) return value.map(toText).filter(Boolean).join(', ');
  if (typeof value === 'object') return value.name || value.value || value.plain_text || value.start || (value.text && value.text.content) || '';
  return value.toString();
};
const mapped = json => {
  const result = {};
  const source = { ...(json.properties || {}), ...json };
  for (const key of Object.keys(source)) result[normalize(key.startsWith('property_') ? key.slice(9) : key)] = source[key];
  return result;
};
const field = (properties, names) => {
  for (const name of names) { const value = toText(properties[name]); if (value) return value; }
  return '';
};
const nodeItems = name => {
  const items = $(name).all();
  if (items.some(item => item.json && item.json.error)) throw new Error('Notion read failed: ' + name);
  return items.map(item => item.json || {});
};
const repeatedEntries = entries => {
  const seen = new Map();
  for (const entry of entries) {
    const text = (entry.text || '').trim();
    const key = normalize(text).slice(0, 120);
    if (!key || key.length < 12) continue;
    const current = seen.get(key) || { text, count: 0, sources: [] };
    current.count += 1;
    if (entry.source && current.sources.length < 5) current.sources.push(entry.source);
    seen.set(key, current);
  }
  return Array.from(seen.values()).filter(entry => entry.count >= 3).slice(0, 10);
};

const systemContextBlocks = nodeItems('System context');
const contextLines = [];
for (const block of systemContextBlocks) {
  const text = getText(block).trim();
  if (text) contextLines.push(block.type && block.type.startsWith('heading_') ? '## ' + text : '- ' + text);
}
const systemContextFull = contextLines.join('\n');
const system_context = systemContextFull.slice(0, 16000);
if (!system_context) throw new Error('System Context is empty');

const noteBlocks = nodeItems('Notes');
const journal = [];
const todos = [];
let section = '';
let journalDate = '';
for (const block of noteBlocks) {
  const text = getText(block).trim();
  if (block.type === 'heading_1' || block.type === 'heading_2') {
    if (text.includes('Journal')) section = 'journal';
    else if (text.includes('Todo') || text.includes('✅')) section = 'todos';
    else if (text.includes('Archive') || text.includes('🗄')) break;
    else section = '';
    continue;
  }
  if (section === 'journal' && block.type === 'heading_3') {
    const match = text.match(/(\d{2})\/(\d{2})\/(\d{4})/);
    journalDate = match ? `${match[3]}-${match[2]}-${match[1]}` : '';
    continue;
  }
  if (!text) continue;
  if (section === 'journal' && inPeriod(journalDate)) journal.push({ date: journalDate, text });
  if (section === 'todos') todos.push({ text, checked: Boolean(block.checked ?? ((block.to_do || {}).checked)) });
}

const objectives = [];
const activeObjectivesWithoutNextStep = [];
for (const row of nodeItems('Objectives')) {
  const p = mapped(row);
  const name = field(p, ['name']);
  if (!name) continue;
  const objective = {
    name,
    status: field(p, ['status']),
    area: field(p, ['area']),
    priority: field(p, ['priority']),
    current_state: field(p, ['currentstate']),
    next_step: field(p, ['nextstep']),
    horizon: field(p, ['horizon']),
  };
  objectives.push(objective);
  if (objective.status === 'Active' && !objective.next_step) {
    activeObjectivesWithoutNextStep.push({
      name: objective.name,
      area: objective.area,
      priority: objective.priority,
      current_state: objective.current_state,
    });
  }
}

const tasks = [];
const staleOpenTasks = [];
const openTasksWithoutProposedOn = [];
for (const row of nodeItems('Tasks')) {
  const p = mapped(row);
  const title = field(p, ['task']);
  if (!title) continue;
  const status = field(p, ['status']);
  const proposed_on = field(p, ['proposedon']);
  const done_on = field(p, ['doneon']);
  const task = { title, status, area: field(p, ['area']), why: field(p, ['why']), feedback: field(p, ['feedback']), proposed_on, done_on };
  if (status === 'Done' && !inPeriod(done_on)) continue;
  if (status === 'Abandoned' && !inPeriod(proposed_on) && !inPeriod(field(p, ['lasteditedtime']))) continue;
  tasks.push(task);
  if (status === 'To do' || !status) {
    const proposedAge = ageDays(proposed_on);
    if (proposedAge !== null && proposedAge > 7) staleOpenTasks.push({ ...task, age_days: proposedAge });
    if (!proposed_on) openTasksWithoutProposedOn.push(task);
  }
}

const dailyBriefBlocks = nodeItems('Daily Briefs');
const daily_briefs = [];
const allDailyBriefDates = [];
const oldDailyBriefDates = [];
let current = null;
for (const block of dailyBriefBlocks) {
  const text = getText(block).trim();
  if (block.type === 'heading_2') {
    const match = text.match(/Daily Brief[^0-9]*(\d{2})\/(\d{2})\/(\d{4})/i);
    const isoDate = match ? `${match[3]}-${match[2]}-${match[1]}` : '';
    if (isoDate) {
      allDailyBriefDates.push(isoDate);
      const briefAge = ageDays(isoDate);
      if (briefAge !== null && briefAge > 30) oldDailyBriefDates.push({ date: isoDate, age_days: briefAge });
    }
    current = inPeriod(isoDate) ? { date: isoDate, content: [] } : null;
    if (current) daily_briefs.push(current);
    continue;
  }
  if (current && text) current.content.push(text);
}

const inbox = [];
const staleInboxItems = [];
const briefedUnarchivedItems = [];
for (const row of nodeItems('AI Inbox')) {
  const p = mapped(row);
  const title = field(p, ['name', 'title']) || '(untitled)';
  const status = field(p, ['status']);
  const captured_at = field(p, ['capturedat', 'createdtime']);
  const briefed_at = field(p, ['briefedat']);
  const item = {
    title,
    status,
    source: field(p, ['source']),
    area: field(p, ['area']),
    captured_at,
    briefed_at,
  };
  inbox.push(item);
  if (status === 'Inbox') {
    const captureAge = ageDays(captured_at);
    if (captureAge !== null && captureAge > 7) staleInboxItems.push({ ...item, age_days: captureAge });
  }
  if (status === 'Briefed') {
    const briefedAge = ageDays(briefed_at || captured_at);
    if (briefedAge !== null && briefedAge > 14) briefedUnarchivedItems.push({ ...item, age_days: briefedAge });
  }
}

const library = [];
const libraryRows = $env.NOTION_LIBRARY_DATABASE_ID ? nodeItems('Library') : [];
for (const row of libraryRows) {
  const p = mapped(row);
  const title = field(p, ['name', 'title']);
  const date = field(p, ['publishedat', 'capturedat', 'createdtime', 'lasteditedtime']);
  if (title && (!date || inPeriod(date))) library.push({ title, date, author: field(p, ['author']), category: field(p, ['category', 'type']), summary: field(p, ['summary', 'highlights']) });
}

const repeatedNoteCandidates = repeatedEntries([
  ...journal.map(entry => ({ text: entry.text, source: `Journal: ${entry.date}` })),
  ...todos.map(entry => ({ text: entry.text, source: entry.checked ? 'Todo: checked' : 'Todo: open' })),
]);
const memory_lint = {
  thresholds: {
    system_context_chars_warning: 12000,
    stale_open_task_days: 7,
    stale_inbox_days: 7,
    briefed_archive_days: 14,
    old_daily_brief_days: 30,
    repeated_note_count: 3,
  },
  page_sizes: {
    system_context_chars: systemContextFull.length,
    system_context_lines: contextLines.length,
    notes_blocks_read: noteBlocks.length,
    weekly_journal_entries: journal.length,
    todo_count: todos.length,
    open_todo_count: todos.filter(todo => !todo.checked).length,
    daily_brief_blocks_read: dailyBriefBlocks.length,
    daily_brief_heading_count: allDailyBriefDates.length,
    inbox_rows_read: inbox.length,
  },
  flags: {
    system_context_long: systemContextFull.length > 12000,
    system_context_truncated: systemContextFull.length > system_context.length,
  },
  stale_open_tasks: staleOpenTasks.slice(0, 25),
  open_tasks_without_proposed_on: openTasksWithoutProposedOn.slice(0, 25),
  active_objectives_without_next_step: activeObjectivesWithoutNextStep.slice(0, 25),
  stale_inbox_items: staleInboxItems.slice(0, 25),
  briefed_unarchived_items: briefedUnarchivedItems.slice(0, 25),
  old_daily_brief_dates: oldDailyBriefDates.slice(0, 25),
  repeated_note_candidates: repeatedNoteCandidates,
};

return [{ json: { ...period, language: $env.WEEKLY_LANGUAGE || 'French', system_context, journal: journal.slice(0, 100), todos: todos.slice(0, 100), objectives: objectives.slice(0, 50), tasks: tasks.slice(0, 150), inbox: inbox.slice(0, 50), daily_briefs: daily_briefs.slice(0, 7), library: library.slice(0, 50), memory_lint } }];

const generated = $input.first().json || {};
if (!Array.isArray(generated.blocks) || !generated.blocks.length) throw new Error('Weekly Review returned no Notion blocks');
const existing = $('Existing reviews').all().map(item => item.json || {}).filter(block => block.id);
const children = [{ object: 'block', type: 'divider', divider: {} }, ...generated.blocks];
const body = existing.length ? { children, after: existing[0].id } : { children };
return [{ json: { body } }];

const generated = $('Memo Bridge /weekly').first().json || {};
if (generated.engine === 'claude' && generated.context_source === 'notion') return [];
return [{ json: { engine: generated.engine || 'none', context_source: generated.context_source || 'missing', week_end: $('Prepare review period').first().json.week_end } }];
